// Define the state for Dijkstra's: (heavy_count, node)
// We use std::pair and std::greater to create a min-heap based on heavy_count
using State = pair<long long, int>; 

/**
 * Checks if a path exists from source to target using at most k heavy edges 
 * given a specific threshold T.
 * This is solved using Dijkstra's algorithm where the path cost is the count of heavy edges.
 */
bool canReach(long long n, const vector<vector<Edge>>& adj, long long source, long long target, long long k, long long T) {
    // D[i] stores the minimum number of heavy edges required to reach node i
    const long long INF_K = k + 1;
    vector<long long> D(n, INF_K); 

    // Min-Priority Queue: stores {heavy_count, node}
    priority_queue<State, vector<State>, greater<State>> pq;

    D[source] = 0;
    pq.push({0, (int)source});

    while (!pq.empty()) {
        auto [h, u] = pq.top();
        pq.pop();

        if (h > D[u]) {
            continue;
        }

        if (u == target) {
            // We found a path to target, and since Dijkstra explores in increasing order of h, 
            // this path is guaranteed to be minimal in heavy count for this threshold T.
            // Since we only push if h <= k, if we reached here, the condition holds.
            return true; 
        }

        for (const auto& edge : adj[u]) {
            int v = edge.neighbor;
            long long w = edge.weight;

            // Determine cost delta: 1 if heavy (w > T), 0 if light (w <= T)
            long long delta = (w > T) ? 1 : 0;

            long long new_h = h + delta;

            if (new_h <= k && new_h < D[v]) {
                D[v] = new_h;
                pq.push({new_h, v});
            }
        }
    }

    // If the loop finishes and target hasn't been reached with <= k heavy edges
    return D[target] <= k;
}


long long solve(long long n, vector<vector<long long>> edges, long long source, long long target, long long k) {
    if (source == target) return 0;

    // 1. Build Adjacency List
    vector<vector<Edge>> adj(n);
    long long maxWeight = 0;

    for (const auto& edge_list : edges) {
        int u = (int)edge_list[0];
        int v = (int)edge_list[1];
        long long w = edge_list[2];

        adj[u].push_back({v, w});
        adj[v].push_back({u, w});

        if (w > maxWeight) {
            maxWeight = w;
        }
    }

    // 2. Binary Search for Minimum T

    // Search range [L, R]. 
    // L = 0 (minimum possible threshold)
    // R = maxWeight + 1. We search up to and including maxWeight.
    long long L = 0;
    long long R = maxWeight + 1; 
    long long minThreshold = -1; 

    // Initial check: Can we reach the target even if ALL edges are light (T >= maxWeight)?
    // We use T = maxWeight.
    if (!canReach(n, adj, source, target, k, maxWeight)) {
        return -1;
    }

    // Binary search for the minimum T such that canReach(T) is true.
    while (L < R) {
        // Mid represents the threshold T we are testing
        // Using L + (R - L) / 2 prevents potential overflow, though unlikely here.
        long long Mid = L + (R - L) / 2;

        if (canReach(n, adj, source, target, k, Mid)) {
            // Success: Mid works. Store it and try for a smaller threshold.
            minThreshold = Mid;
            R = Mid;
        } else {
            // Failure: Mid is too low; we need a higher threshold.
            L = Mid + 1;
        }
    }

    // Since we pre-checked that a solution exists (at least for T=maxWeight), 
    // minThreshold must have been updated.
    return minThreshold;
}

