// Helper struct for PQ elements: {heavy_count, node}
// We use int for heavy_count (max K <= 10^3) and node index (max N-1 <= 10^3).
using State = pair<int, int>; 

/**
 * Checks if a valid path exists from source to target using at most K heavy edges 
 * for a given threshold T. Uses Dijkstra's algorithm where path cost is the heavy edge count.
 */
bool canReach(long long T, int N, const vector<vector<pair<int, long long>>>& adj, int source, int target, int K) {

    // D[i] = minimum heavy edges to reach node i
    // Initialize to K + 1 (a value guaranteed to be larger than any valid count K)
    vector<int> D(N, K + 1);

    // Min-heap: {heavy_count, node}
    // std::priority_queue uses std::greater for Min Heap.
    priority_queue<State, vector<State>, greater<State>> pq;

    D[source] = 0;
    pq.push({0, source});

    while (!pq.empty()) {
        auto [h, u] = pq.top();
        pq.pop();

        if (h > D[u]) {
            continue;
        }

        if (u == target) {
            return true; 
        }

        for (const auto& edge : adj[u]) {
            int v = edge.first;
            long long w = edge.second;

            // Determine cost delta: 1 if heavy (w > T), 0 if light (w <= T)
            int delta = (w > T) ? 1 : 0;

            int new_h = h + delta;

            // Check constraints: Must be <= K, and must improve the current shortest path found for v
            if (new_h <= K && new_h < D[v]) {
                D[v] = new_h;
                pq.push({new_h, v});
            }
        }
    }

    return D[target] <= K; 
}


