        D[source] = 0;
        pq.push([0, source]); // [heavy_count, node]

        while (!pq.isEmpty()) {
            const [h, u] = pq.pop();

            if (h > D[u]) {
                continue;
            }

            if (u === target) {
                return true; 
            }

            for (const { neighbor: v, weight: w } of adj[u]) {
