    // Search range: [L, R]. 
    // L = 0 (minimum possible threshold)
    // R = maxWeight + 1 (A value guaranteed to make all edges light, plus one for boundary safety)
    let L = 0;
    let R = maxWeight + 1; 
    let minThreshold = maxWeight + 1; 

    while (L < R) {
