// Helper MinHeap implementation
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Comparison function: a < b means a has higher priority (smaller heavy count)
    compare(i, j) {
        // We store [heavy_count, node]
        return this.heap[i][0] < this.heap[j][0];
    }

    push(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(currentIndex, parentIndex)) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return root;
    }

    bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this.getLeftChildIndex(currentIndex);
            let right = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            if (left <= lastIndex && this.compare(left, smallest)) {
                smallest = left;
            }
            if (right <= lastIndex && this.compare(right, smallest)) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}

function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // 1. Build Adjacency List (Undirected Graph)
    const adj = Array(n).fill(0).map(() => []);
    let maxWeight = 0;

    for (const [u, v, w] of edges) {
        adj[u].push({ neighbor: v, weight: w });
        adj[v].push({ neighbor: u, weight: w });
        if (w > maxWeight) {
            maxWeight = w;
        }
    }

    // 2. Check Function: Can we reach target using at most k heavy edges for a given threshold T?
    const canReach = (T) => {
        // D[i] stores the minimum number of heavy edges to reach node i
        const D = Array(n).fill(k + 1); 
        const pq = new MinPriorityQueue();

        D[source] = 0;
        pq.push([0, source]); // [heavy_count, node]

        while (!pq.isEmpty()) {
            const [h, u] = pq.pop();

            if (h > D[u]) {
                continue;
            }

            if (u === target) {
                // We found a path, and since Dijkstra minimizes h, this is the minimum h.
                // Since we checked h <= k implicitly by initializing D[i] to k+1, 
                // if we reached here, h <= k must hold, but explicitly checking is safer.
                return true; 
            }

            for (const { neighbor: v, weight: w } of adj[u]) {
                // Determine cost delta: 1 if heavy (w > T), 0 if light (w <= T)
                const delta = (w > T) ? 1 : 0;

                const new_h = h + delta;

                if (new_h <= k && new_h < D[v]) {
                    D[v] = new_h;
                    pq.push([new_h, v]);
                }
            }
        }

        // If the loop finishes and we haven't returned true, check the final state for target
        return D[target] <= k;
    };

    // Initial check: Can we reach it even if T is huge (all edges light)?
    // If maxWeight is 0 (no edges), we already handled source == target. If n>1 and no edges, we won't reach.
    if (!canReach(maxWeight)) {
        // If we cannot reach it even when T >= maxWeight (i.e., all edges are light), 
        // then no path exists, regardless of threshold.
        return -1;
    }

    // 3. Binary Search for Minimum T

    // Search range: [L, R]. 
    // L = 0 (minimum possible threshold)
    // R = maxWeight + 1 (A value guaranteed to make all edges light, plus one for boundary safety)
    let L = 0;
    let R = maxWeight + 1; 
    let minThreshold = maxWeight + 1; // Initialize to impossible value

    while (L < R) {
        // Mid represents the threshold T we are testing
        const Mid = Math.floor(L + (R - L) / 2);

        if (canReach(Mid)) {
            // Success: Mid works. Store it and try for a smaller threshold.
            minThreshold = Mid;
            R = Mid;
        } else {
            // Failure: Mid is too low; we need a higher threshold to make more edges light.
            L = Mid + 1;
        }
    }

    // Since we already checked if a path exists using canReach(maxWeight), 
    // minThreshold must hold a valid answer <= maxWeight.
    return minThreshold;
}
